
CREATE TABLE IF NOT EXISTS matriz (
    resultado INTEGER PRIMARY KEY,
    motivacao TEXT,
    impressao TEXT,
    expressao TEXT,
    destino TEXT,
    missao TEXT,
    dia_natalicio TEXT,
    talento_oculto TEXT,
    no_psiquico TEXT,
    tendencias_ocultas TEXT,
    resposta_subconsciente TEXT,
    desafios_ciclo TEXT,
    potencialidade_profissional TEXT,
    desafio_aniversario TEXT,
    triangulo TEXT
);

DELETE FROM matriz;
